/**
 *
 * @type {function(*=, *, *): *}
 */
export var setPropVal = (utils.setPropVal = function(object, keySet, value, updateCallback) {
    keySet = keySet.replace(/\[(\w+)]/g, '.$1'); // convert indexes to properties
    keySet = keySet.replace(/^\./, ''); // strip a leading dot
    var keys = keySet.split('.');
    var add = function(obj) {
        var key = keys.shift();
        if (key === null || keys.length === 0) {
            updateCallback ? updateCallback(obj, key, value) : (obj[key] = value);
            return false;
        } else if (obj[key] === null || typeof obj[key] !== 'object') {
            obj[key] = !isNaN(parseInt(keys[0])) ? [] : {};
        }
        add(obj[key]);
    };
    add(object);
    return object;
});

