export function each(obj, fn) {
    if (typeof obj !== 'object') {
        return false;
    }

    if (isArray(obj) || typeof obj.length === 'number') {
        Array.prototype.forEach.call(obj, fn);
    } else {
        for (var attr in obj) {
            if (obj.hasOwnProperty(attr)) {
                fn(obj[attr], attr, obj);
            }
        }
    }
}

utils.each = each;

